/**
 * MMS Domain Services
 *
 * Central export for all domain services in the MMS system.
 * Each service encapsulates business logic for a specific domain.
 *
 * Services extend BaseService for:
 * - OpenTelemetry distributed tracing
 * - Structured logging with Pino
 * - Database transaction management
 * - Consistent error handling
 *
 * @see specs/004-domain-services.md
 */

// =============================================================================
// Auth Service
// =============================================================================
export {
  AuthService,
  getAuthService,
  type AuthenticatedUser,
  type LoginRequest,
  type LoginResponse,
  type RefreshRequest,
  type RefreshResponse,
  type JwtPayload,
  type SessionData,
} from './auth';

// =============================================================================
// Fleet Service
// =============================================================================
export {
  FleetService,
  getFleetService,
  type FleetListFilters,
  type TrainListFilters,
  type PaginationOptions,
  type PaginatedResult,
  type FleetStatistics,
  type TrainWithFleet,
  type FitnessStatusChangeRequest,
  type MileageUpdateRequest,
} from './fleet';

// =============================================================================
// Unavailability Service
// =============================================================================
export {
  UnavailabilityService,
  getUnavailabilityService,
  type CreateEventRequest,
  type ResolveEventRequest,
  type EventListFilters,
  type PMConflict,
  type EventWithTrain,
  type OptimizerConstraints,
} from './unavailability';

// =============================================================================
// Service Demand Service
// =============================================================================
export {
  ServiceDemandService,
  getServiceDemandService,
  type DayType,
  type TimePeriod,
  type DemandConfig,
  type AvailabilityValidation,
  type DemandViolation,
  type ProposedPM,
  type CreateDemandRequest,
  type DemandListFilters,
  type FleetAvailabilitySummary,
} from './service-demand';

// =============================================================================
// Route Utilization Service
// =============================================================================
export {
  RouteUtilizationService,
  getRouteUtilizationService,
  type UtilizationDayType,
  type ConfidenceLevel,
  type RateSource,
  type DailyRateResult,
  type MileageProjection,
  type RouteProfileWithMeta,
  type CreateProfileRequest,
  type UpdateProfileRequest,
  type ProfileListFilters,
  type FleetAverageResult,
  type TrainProjectionInfo,
  type ProjectionAccuracyAnalysis,
} from './route-utilization';

// =============================================================================
// Ingestion Service
// =============================================================================
export {
  IngestionService,
  getIngestionService,
  type AnomalyType,
  type DbAnomalyType,
  type AnomalyRecord,
  type MeterEventRecord,
  type FileWatcherConfig,
  type FileValidationResult,
  type IngestionResult,
  type MileageReadingFilters,
  type MileageReadingWithTrain,
  type AnomalyQueryFilters,
  type AnomalyWithDetails,
} from './ingestion';

// =============================================================================
// PM Scheduler Service
// =============================================================================
export {
  PMSchedulerService,
  getPMSchedulerService,
  type PmDueResult,
  type ComplianceWindow,
  type MaterialAvailability,
  type MaterialConstraintResult,
  type TrackAllocation,
  type SchedulingResultItem,
  type SchedulingExplanation,
  type SchedulingResult,
  type SchedulePmRequest,
  type MovePmRequest,
  type TacticalScheduleRequest,
} from './pm-scheduler';

// =============================================================================
// Baseline Service
// =============================================================================
export {
  BaselineService,
  getBaselineService,
  type BaselineStatus,
  type BaselineListFilters,
  type BaselinePaginationOptions,
  type PaginatedBaselineResult,
  type PublishBaselineRequest,
  type PlanValidationResult,
  type PlanConflict,
  type PlanWarning,
  type BaselineSummary,
  type BaselinePmScheduleWithTrain,
  type BaselineMileageProjectionWithTrain,
} from './baseline';

// =============================================================================
// Drift Monitor Service
// =============================================================================
export {
  DriftMonitorService,
  getDriftMonitorService,
  DEFAULT_DRIFT_THRESHOLDS,
  type DriftThresholds,
  type DriftDirection,
  type PMDrift,
  type TrainDriftAnalysis,
  type AlertSeverity,
  type AlertType,
  type DriftAlert,
  type DriftAnalysisSkipped,
  type DriftAnalysisSuccess,
  type DriftAnalysisResult,
  type DriftHistoryFilters,
  type PaginatedDriftHistory,
} from './drift-monitor';

// =============================================================================
// Man-hour Leveling Service
// =============================================================================
export {
  ManHourLevelingService,
  getManHourLevelingService,
  LEVELING_STRATEGIES,
  type AdjustmentType,
  type RiskLevel,
  type AdjustmentStatus,
  type LevelingStrategy,
  type LevelingTimePeriod,
  type RequiredHours,
  type AvailableHours,
  type ProjectionData,
  type ProposedAdjustment,
  type LevelingMetrics,
  type LevelingImprovement,
  type LevelingResult,
  type GenerateProjectionsRequest,
  type UpdateCapacityRequest,
  type ProjectionFilters,
  type AdjustmentFilters,
  type PaginatedResult as ManHourPaginatedResult,
} from './man-hour-leveling';

// =============================================================================
// Costing Service
// =============================================================================
export {
  CostingService,
  getCostingService,
  OVERHEAD_RATE,
  INFLATION_RATE,
  DISCOUNT_RATE,
  DEFAULT_HORIZON_YEARS,
  VARIANCE_TOLERANCE,
  type CostBreakdown,
  type YearlyCost,
  type TCOSummary,
  type TCOProjection,
  type BudgetFigures,
  type ActualFigures,
  type VarianceFigures,
  type VarianceStatus,
  type CostVariance,
  type LaborRate,
  type CalculatePMCostRequest,
  type ProjectTCORequest,
  type CalculateVarianceRequest,
} from './costing';

// =============================================================================
// Material Service
// =============================================================================
export {
  MaterialService,
  getMaterialService,
  type InventoryWithDepot,
  type ReservationStatus,
  type ReservationWithDetails,
  type InventoryFilters,
  type ReservationFilters,
  type PaginationOptions as MaterialPaginationOptions,
  type PaginatedResult as MaterialPaginatedResult,
  type FulfillReservationRequest,
  type FulfillReservationResult,
} from './material';

// =============================================================================
// Simulation Service
// =============================================================================
export {
  SimulationService,
  getSimulationService,
  type ScenarioStatus,
  type DeltaType,
  type EntityType,
  type ForkSource,
  type CreateScenarioRequest,
  type ScenarioChange,
  type MaterializedPmRecord,
  type MaterializedScenario,
  type PMDifference,
  type PMDifferenceSummary,
  type ManhourDifferenceSummary,
  type CostDifferenceSummary,
  type ScenarioComparisonResult,
  type ScenarioListFilters,
  type ScenarioPaginationOptions,
  type PaginatedScenarioResult,
  type ScenarioWithMeta,
  type PromoteScenarioRequest,
} from './simulation';

// =============================================================================
// Export Service
// =============================================================================
export {
  getExportService,
  type ExportService,
  type ExportFormat,
  type ExportJobStatus,
  type PmScheduleExportRequest,
  type ReportType,
  type ReportExportRequest,
} from './export';

// =============================================================================
// Maximo Client (REST API)
// =============================================================================
export {
  MaximoClient,
  getMaximoClient,
  resetMaximoClient,
  type MaximoConfig,
  type MaximoWoStatus as MaximoClientWoStatus,
  type MaximoWorkOrderCreatePayload,
  type MaximoWorkOrderUpdatePayload,
  type MaximoWorkOrder as MaximoClientWorkOrder,
} from './maximo-client';

// =============================================================================
// Maximo Sync Service
// =============================================================================
export {
  MaximoSyncService,
  getMaximoSyncService,
  MAXIMO_TO_MMS_STATUS,
  LOCKED_MAXIMO_STATUSES,
  MAXIMO_STATUS_LABELS,
  type MaximoWoStatus,
  type SyncStatus,
  type SyncOperation,
  type EditValidationResult,
  type PushResult,
  type PullResult,
  type PullDetail,
  type ConflictResolution,
  type ShadowRecordWithPm,
  type MaximoWorkOrderCreate,
  type MaximoWorkOrder,
  type SyncStats,
  type ShadowRecordFilters,
  type PaginatedShadowRecords,
} from './maximo-sync';

// =============================================================================
// Maximo Polling Service (Fallback Mechanism)
// =============================================================================
export {
  MaximoPollingService,
  getMaximoPollingService,
  DEFAULT_POLLING_CONFIG,
  type SyncMode,
  type PollingConfig,
  type WebhookHealthStatus,
  type PollingResult,
} from './maximo-polling';

// =============================================================================
// Strategic Planner Service
// =============================================================================
export {
  StrategicPlannerService,
  getStrategicPlannerService,
  DEFAULT_CONFIG as STRATEGIC_PLANNER_DEFAULT_CONFIG,
  type StrategicPlannerConfig,
  type PMRequirement,
  type StrategicAllocation,
  type ConstraintEnvelope,
  type PlanValidation,
  type PlanViolation,
  type PlanWarning as StrategicPlanWarning,
  type PlanMetrics,
  type StrategicPlanResult,
  type GenerationStats,
  type ProgressCallback,
  type GeneratePlanRequest,
} from './strategic-planner';

// =============================================================================
// Notification Service
// =============================================================================
export {
  NotificationService,
  getNotificationService,
  type NotificationType,
  type NotificationSeverity,
  type DigestMode,
  type NotificationStatus,
  type TypePreference,
  type UserPreferences,
  type SmtpConfig,
  type SendNotificationRequest,
  type SendNotificationResult,
  type EmailContent,
  type NotificationLogFilters,
  type PaginationOptions as NotificationPaginationOptions,
  type PaginatedResult as NotificationPaginatedResult,
} from './notification';

// =============================================================================
// Baseline Assumption Service (Cold Start / Data Migration)
// =============================================================================
export {
  BaselineAssumptionService,
  getBaselineAssumptionService,
  type AssumptionType,
  type ConfidenceLevel as AssumptionConfidenceLevel,
  type ReviewStatus,
  type CreateAssumptionRequest,
  type UpdateAssumptionRequest,
  type ReviewAssumptionRequest,
  type ApplyAssumptionRequest,
  type InferFromCommissioningRequest,
  type InferFromHigherPmRequest,
  type AssumptionFilters,
  type PaginationOptions as AssumptionPaginationOptions,
  type PaginatedResult as AssumptionPaginatedResult,
  type AssumptionWithDetails,
  type ReviewQueueSummary,
  type InferenceResult,
} from './baseline-assumption';

