   179→// =============================================================================
   180→
   181→/**
   182→ * Baseline Assumption Service
   183→ *
   184→ * Manages PM history assumptions for cold start data migration scenarios.
   185→ */
   186→export class BaselineAssumptionService extends BaseService {
   187→  constructor() {
