   169→}
   170→
   171→/** PM cost calculation request */
   172→export interface CalculatePMCostRequest {
   173→  pmScheduleId: string;
   174→  includeProjected?: boolean;
   175→}
   176→
   177→/** TCO projection request */
   178→export interface ProjectTCORequest {
   179→  horizonYears?: number;
