/**
 * MMS Material Service
 *
 * Manages inventory positions and material reservations for PM scheduling.
 * Materials are a constraint for PM scheduling - PMs cannot proceed without
 * required blocking parts.
 *
 * Key responsibilities:
 * - Query inventory positions with filtering (depot, part number, low stock)
 * - Query material reservations with filtering (PM, status)
 * - Fulfill material reservations (mark as delivered)
 * - Support soft/hard reservation lifecycle
 *
 * Integration:
 * - Inventory snapshots come from Maximo/ERP daily
 * - Reservations are created when PMs are scheduled
 * - Soft reservations auto-expire if PM moves
 *
 * Constraint enforcement:
 * - BLOCKING parts with SOFT reservation: Warning, PM can proceed
 * - BLOCKING parts without reservation: PM cannot be scheduled
 *
 * @see specs/004-domain-services.md
 * @see specs/005-api.md Section 5.11
 */

import { eq, and, sql, desc, type SQL } from 'drizzle-orm';
import { BaseService } from '../lib/services/base';
import {
  inventoryPositions,
  materialReservations,
  depots,
  pmSchedule,
  pmTypes,
  trains,
  users,
} from '../lib/db/schema';
import { NotFoundError, ValidationError } from '../lib/errors';

// =============================================================================
// Types
// =============================================================================

/** Inventory position with depot info */
export interface InventoryWithDepot {
  id: string;
  depotId: string;
  depotCode: string;
  depotName: string;
  partNumber: string;
  partDescription: string | null;
  quantityOnHand: number;
  quantityReserved: number;
  quantityAvailable: number;
  quantityOnOrder: number | null;
  reorderPoint: number | null;
  reorderQuantity: number | null;
  nextDeliveryDate: string | null;
  nextDeliveryQuantity: number | null;
  unitCost: number | null;
  currency: string | null;
  lastSyncAt: string | null;
  sourceSystem: string | null;
  isLowStock: boolean;
}

/** Reservation status for filtering */
export type ReservationStatus = 'PENDING' | 'FULFILLED' | 'EXPIRED';

/** Material reservation with related info */
export interface ReservationWithDetails {
  id: string;
  pmScheduleId: string;
  inventoryPositionId: string;
  partNumber: string;
  quantityReserved: number;
  reservationType: 'SOFT' | 'HARD';
  reservedAt: string;
  reservedBy: string | null;
  reservedByName: string | null;
  expiresAt: string | null;
  fulfilledAt: string | null;
  fulfilledQuantity: number | null;
  status: ReservationStatus;
  pm: {
    id: string;
    trainNumber: string;
    pmCode: string;
    targetDate: string;
  };
  depot: {
    id: string;
    code: string;
    name: string;
  };
}

/** Filters for inventory listing */
export interface InventoryFilters {
  depotId?: string;

/**
 * MMS Man-hour Leveling Service
 *
 * Projects workforce requirements and generates adjustment recommendations
 * to balance workload across time periods. Prevents overload/underutilization
 * of depot maintenance resources over the tactical planning horizon.
 *
 * Key responsibilities:
 * - Calculate raw man-hour projections from PM schedule
 * - Identify overloaded and underutilized weeks
 * - Apply leveling strategies in priority order
 * - Persist projections and adjustments
 * - Support approval workflow for adjustments
 *
 * Leveling Strategies (priority order):
 * 1. ADVANCE_PM (1.1x cost, LOW risk, max 40h/week)
 * 2. DEFER_PM (1.05x cost, LOW risk, max 40h/week)
 * 3. ADD_OVERTIME (1.5x cost, NO risk, max 80h/week)
 * 4. CROSS_DEPOT (1.3x cost, MEDIUM risk, max 60h/week)
 * 5. ADD_CONTRACTOR (2.0x cost, MEDIUM risk, max 100h/week)
 * 6. MANUAL_REVIEW (flagged for high unresolvable overload)
 *
 * Utilization Targets:
 * - Target: 85%
 * - Minimum: 70% (underutilized below this)
 * - Maximum: 100% (overloaded above this)
 *
 * @see specs/004-domain-services.md Section 4.6
 */

import {
  eq,
  and,
  gte,
  lte,
  desc,
  asc,
  sql,
  inArray,
  isNull,
  or,
  count,
  type SQL,
} from 'drizzle-orm';
import {
  addDays,
  addWeeks,
  startOfWeek,
  endOfWeek,
  format,
  differenceInWeeks,
  parseISO,
  isBefore,
  isAfter,
} from 'date-fns';
import { BaseService } from '../lib/services/base';
import {
  manhourCapacity,
  manhourProjections,
  manhourAdjustments,
  pmSchedule,
  pmTypes,
  depots,
  trains,
  laborRates,
  type ManhourCapacity,
  type ManhourProjection,
  type ManhourAdjustment,
} from '../lib/db/schema';
import { NotFoundError, ValidationError, ConflictError } from '../lib/errors';

// =============================================================================
// Constants
// =============================================================================

/** Minimum utilization percentage (underutilized below this) */
const MIN_UTILIZATION = 0.7;

/** Maximum utilization percentage (overloaded above this) */
const MAX_UTILIZATION = 1.0;

/** Default base labor rate per hour (SGD) */
const DEFAULT_BASE_RATE = 85;

/** Minimum meaningful shift in hours (don't bother with tiny adjustments) */
const MIN_SHIFT_HOURS = 8;

/** Minimum overtime hours to add */
const MIN_OVERTIME_HOURS = 4;

// =============================================================================
// Types
// =============================================================================

/** Leveling strategy types */
export type AdjustmentType =
  | 'ADVANCE_PM'
  | 'DEFER_PM'
  | 'ADD_OVERTIME'
  | 'CROSS_DEPOT'
  | 'ADD_CONTRACTOR'
  | 'MANUAL_REVIEW';

/** Risk levels for adjustments */
export type RiskLevel = 'NONE' | 'LOW' | 'MEDIUM' | 'HIGH';

/** Adjustment status in workflow */
export type AdjustmentStatus = 'PROPOSED' | 'APPROVED' | 'REJECTED' | 'APPLIED';

/** Leveling strategy configuration */
export interface LevelingStrategy {
  type: AdjustmentType;
  priority: number;
  maxHoursPerWeek: number;
  costMultiplier: number;
  riskLevel: RiskLevel;
}

/** All leveling strategies in priority order */
export const LEVELING_STRATEGIES: LevelingStrategy[] = [
  { type: 'ADVANCE_PM', priority: 1, maxHoursPerWeek: 40, costMultiplier: 1.1, riskLevel: 'LOW' },
  { type: 'DEFER_PM', priority: 2, maxHoursPerWeek: 40, costMultiplier: 1.05, riskLevel: 'LOW' },
  { type: 'ADD_OVERTIME', priority: 3, maxHoursPerWeek: 80, costMultiplier: 1.5, riskLevel: 'NONE' },
  { type: 'CROSS_DEPOT', priority: 4, maxHoursPerWeek: 60, costMultiplier: 1.3, riskLevel: 'MEDIUM' },
  {
    type: 'ADD_CONTRACTOR',
    priority: 5,
    maxHoursPerWeek: 100,
    costMultiplier: 2.0,
    riskLevel: 'MEDIUM',
  },
];

/** Time period for projections */
export interface LevelingTimePeriod {
  start: Date;
  end: Date;
}

/** Required hours breakdown */
export interface RequiredHours {
  pm: number;
  corrective: number;
  overhaul: number;
  total: number;
}

/** Available hours breakdown */
export interface AvailableHours {
  regular: number;

/**
