} from '../lib/errors';

// =============================================================================
// Types
// =============================================================================

/** Day type enum values */
export type DayType = 'WEEKDAY' | 'SATURDAY' | 'SUNDAY' | 'HOLIDAY';

/** Time period for peak requirements */
export type TimePeriod = 'PEAK_AM' | 'MIDDAY' | 'PEAK_PM' | 'EVENING' | 'ALL_DAY';

/** Demand configuration for a specific fleet/date */
export interface DemandConfig {
  fleetId: string;
  fleetCode: string;
  date: string;
  dayType: DayType;
  minTrainsRequired: number;
  standbyBuffer: number;
  totalRequired: number; // minTrainsRequired + standbyBuffer
  peakAmRequirement: number | null;
  middayRequirement: number | null;
  peakPmRequirement: number | null;
  eveningRequirement: number | null;
  source: 'CONFIG' | 'DEFAULT';
  sourceRecord: ServiceDemand | null;
}

/** Availability validation result */
