/**
 * MMS Unavailability Service
 *
 * Tracks trains that are out of service due to corrective maintenance,
 * incidents, collisions, or other events. This is a CRITICAL v2.1 service
 * that integrates with Maximo CMMS and provides constraints to the optimizer.
 *
 * Key responsibilities:
 * - Create/resolve unavailability events
 * - Automatically sync train fitness status
 * - Detect conflicts with scheduled PM
 * - Provide active events for optimizer constraints
 * - Support Maximo work order integration
 *
 * Business rules:
 * - ACTIVE events update train fitness to restriction_level (RESTRICTED/GROUNDED)
 * - RESOLVED events restore train fitness to FIT (unless other active events exist)
 * - Events with blocks_run_assignment=true prevent optimizer from assigning train
 * - Events with blocks_pm_scheduling=true prevent PM scheduler from planning train
 *
 * @see specs/003-database-schema.md Section 3.2.3 (Unavailability Events)
 * @see specs/004-domain-services.md Section 4.2.5 (Unavailability Service)
 */

import { eq, and, inArray, sql, desc, count, gte, lte } from 'drizzle-orm';
import type { SQL } from 'drizzle-orm';
import { BaseService, MmsAttributes } from '../lib/services/base';
import {
  unavailabilityEvents,
  trains,
  pmSchedule,
  type UnavailabilityEvent,
  type NewUnavailabilityEvent,
  type Train,
} from '../lib/db/schema';
import {
  NotFoundError,
  TrainNotFoundError,
  BusinessRuleError,
  ConflictError,
} from '../lib/errors';

// =============================================================================
// Types
// =============================================================================

/** Unavailability event types */
type UnavailabilityType = 'CORRECTIVE' | 'INCIDENT' | 'COLLISION' | 'VANDALISM' | 'EXTERNAL' | 'PLANNED_OUTAGE';

/** Event status */
type UnavailabilityStatus = 'ACTIVE' | 'RESOLVED';

/** Restriction level (maps to fitness status) */
type RestrictionLevel = 'RESTRICTED' | 'GROUNDED';

/** Create event request */
export interface CreateEventRequest {
  trainId: string;
  eventType: UnavailabilityType;
  restrictionLevel: RestrictionLevel;
  description?: string;
  failureCode?: string;
  affectedSystem?: string;
  estimatedRepairHours?: number;
  estimatedReturnDate?: string;
  sourceSystem?: string;
  externalReference?: string;
  externalStatus?: string;
  blocksPmScheduling?: boolean;
  blocksRunAssignment?: boolean;
  reportedBy?: string;
}

/** Resolve event request */
export interface ResolveEventRequest {
  eventId: string;
  actualReturnDate: string;
  resolutionNotes?: string;
  resolvedBy?: string;
}

/** Query filters for listing events */
export interface EventListFilters {
  trainId?: string;
  trainIds?: string[];
  status?: UnavailabilityStatus;
  eventType?: UnavailabilityType | UnavailabilityType[];
  restrictionLevel?: RestrictionLevel;
  sourceSystem?: string;
  dateFrom?: string;
  dateTo?: string;
  blocksPmScheduling?: boolean;
  blocksRunAssignment?: boolean;
}

/** PM conflict detection result */
export interface PMConflict {
  pmScheduleId: string;
  trainId: string;
  trainNumber: string;

